function openModal(cid) {
  var d = customers[cid];
  if (!d) return;
  var h = '';
  h += '<div class="modal-header"><h2>' + d.name + '</h2><button class="modal-close" onclick="closeModal()">✕</button></div>';
  h += '<div class="modal-body">';

  // Frontmatter
  h += '<div class="fm-grid">';
  var fields = [
    ['国家', d.country || ''],
    ['阶段', d.stage || ''],
    ['热度', d.heat || ''],
    ['最后联系', d.lastContact || '']
  ];
  for (var i = 0; i < fields.length; i++) {
    h += '<div class="fm-item"><div class="fm-label">' + fields[i][0] + '</div><div class="fm-value">' + fields[i][1] + '</div></div>';
  }
  h += '</div>';

  // Drivers
  if (d.drivers && d.drivers.length) {
    h += '<div class="section"><div class="section-title">📋 驱动因子</div><div class="driver-list">';
    for (var j = 0; j < d.drivers.length; j++) {
      var dr = d.drivers[j];
      var cls = dr.level === 'red' ? 'driver-item-red' : 'driver-item-yellow';
      var icon = dr.level === 'red' ? '🔴' : '🟡';
      h += '<div class="driver-item ' + cls + '"><span class="driver-icon">' + icon + '</span><div><strong>' + dr.title + '</strong><div style="color:#999;font-size:0.85em;margin-top:2px;">' + dr.detail + '</div></div></div>';
    }
    h += '</div></div>';
  }

  // Chat
  if (d.chat && d.chat.length) {
    h += '<div class="section"><div class="section-title">💬 聊到哪了</div><div class="chat-snippet">';
    for (var k = 0; k < d.chat.length; k++) {
      var cl = d.chat[k];
      h += '<div class="chat-line"><span class="chat-who ' + (cl.who === 'me' ? 'chat-who-me' : 'chat-who-cust') + '">' + (cl.who === 'me' ? '我' : '客') + '</span><span class="chat-time">' + cl.time + '</span>' + cl.text + '</div>';
    }
    h += '</div></div>';
  }

  // Key numbers
  if (d.nums && d.nums.length) {
    h += '<div class="section"><div class="section-title">🔢 关键数字</div>';
    for (var m = 0; m < d.nums.length; m++) {
      h += '<div class="key-num">' + d.nums[m] + '</div>';
    }
    h += '</div>';
  }

  // Next step
  if (d.steps) {
    h += '<div class="section"><div class="section-title">→ 下一步</div><div style="font-size:0.9em;line-height:1.7;white-space:pre-line">' + d.steps + '</div></div>';
  }

  h += '</div>';
  h += '<div class="modal-footer"><button class="btn btn-primary">✏️ 起草回复</button><button class="btn">🔍 深度分析</button><button class="btn">✅ 标记已处理</button></div>';

  document.getElementById('modal').innerHTML = h;
  document.getElementById('overlay').classList.add('show');
}

function closeModal() {
  document.getElementById('overlay').classList.remove('show');
}

document.addEventListener('keydown', function(e) {
  if (e.key === 'Escape') closeModal();
});
